import java.io.*;
import java.util.*;

public class Main {
    static final int N = 100001;
    static final int LG = 17;  // Sufficient for up to 100,000 nodes

    static ArrayList<Integer>[] adj = new ArrayList[N];
    static int[] level = new int[N];
    static int[][] ancestors = new int[N][LG];
    static int n;

    static {
        for (int i = 0; i < N; i++) {
            adj[i] = new ArrayList<>();
            Arrays.fill(ancestors[i], -1);
        }
    }

    static void dfs(int node, int parent, int lvl) {
        level[node] = lvl;
        ancestors[node][0] = parent;

        for (int child : adj[node]) {
            if (child != parent) {
                dfs(child, node, lvl + 1);
            }
        }
    }

    static void preprocess() {
        for (int j = 1; j < LG; j++) {
            for (int node = 1; node <= n; node++) {
                int ancestor = ancestors[node][j - 1];
                ancestors[node][j] = (ancestor == -1) ? -1 : ancestors[ancestor][j - 1];
            }
        }
    }

    static int lca(int u, int v) {
        if (level[u] < level[v]) {
            int temp = u;
            u = v;
            v = temp;
        }

        int diff = level[u] - level[v];
        for (int j = 0; j < LG; j++) {
            if ((diff & (1 << j)) != 0) {
                u = ancestors[u][j];
            }
        }

        if (u == v) {
            return u;
        }

        for (int j = LG - 1; j >= 0; j--) {
            if (ancestors[u][j] != -1 && ancestors[u][j] != ancestors[v][j]) {
                u = ancestors[u][j];
                v = ancestors[v][j];
            }
        }

        return ancestors[u][0];
    }

    static int getDistance(int u, int v) {
        int lcaOfUV = lca(u, v);
        return level[u] + level[v] - 2 * level[lcaOfUV];
    }

    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer tokenizer = new StringTokenizer(reader.readLine());

        n = Integer.parseInt(tokenizer.nextToken());
        int u = Integer.parseInt(tokenizer.nextToken());
        int v = Integer.parseInt(tokenizer.nextToken());

        for (int i = 1; i < n; i++) {
            tokenizer = new StringTokenizer(reader.readLine());
            int ui = Integer.parseInt(tokenizer.nextToken());
            int vi = Integer.parseInt(tokenizer.nextToken());
            adj[ui].add(vi);
            adj[vi].add(ui);
        }

        dfs(1, -1, 0);
        preprocess();

        System.out.println(getDistance(u, v));
    }
}

