const readline = require('readline');

const N = 100005;
const LG = 18; // Adjusted LG for JavaScript equivalent

let adj = Array.from({ length: N }, () => []);
let level = Array(N).fill(0);
let ancestors = Array.from({ length: N }, () => Array(LG).fill(-1));
let n;

function dfs(node, parent = -1, lvl = 0) {
    level[node] = lvl;
    ancestors[node][0] = parent;
    for (const child of adj[node]) {
        if (child !== parent) {
            dfs(child, node, lvl + 1);
        }
    }
}

function preprocess() {
    for (let j = 1; j < LG; j++) {
        for (let node = 1; node <= n; node++) {
            let ancestor = ancestors[node][j - 1];
            if (ancestor !== -1) {
                ancestors[node][j] = ancestors[ancestor][j - 1];
            }
        }
    }
}

function lca(u, v) {
    if (level[u] < level[v]) {
        [u, v] = [v, u]; // Swap u and v so that u is always deeper or at the same level as v
    }

    // Bring u and v to the same level
    let diff = level[u] - level[v];
    for (let j = 0; j < LG; j++) {
        if ((diff >> j) & 1) {
            u = ancestors[u][j];
        }
    }

    if (u === v) {
        return v;
    }

    // Move u and v up until they meet at the LCA
    for (let j = LG - 1; j >= 0; j--) {
        if (ancestors[u][j] !== -1 && ancestors[u][j] !== ancestors[v][j]) {
            u = ancestors[u][j];
            v = ancestors[v][j];
        }
    }

    return ancestors[u][0];
}

function get_distance(u, v) {
    let lca_of_uv = lca(u, v);
    return level[u] + level[v] - 2 * level[lca_of_uv];
}

function main() {
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });

    let inputLines = [];
    rl.on('line', (line) => {
        inputLines.push(line.trim());
    });

    rl.on('close', () => {
        let inputIndex = 0;
        let firstLine = inputLines[inputIndex++].split(' ').map(Number);
        n = firstLine[0]; // First number is the number of nodes

        // Handle edge case of single node
        if (n === 1) {
            console.log(0);
            return;
        }

        // Second and third numbers are u and v
        let u = firstLine[1];
        let v = firstLine[2];

        for (let i = 1; i < n; i++) {
            if (inputIndex >= inputLines.length) {
                console.error('Input lines are less than expected');
                return;
            }
            let [ui, vi] = inputLines[inputIndex++].split(' ').map(Number);
            adj[ui].push(vi);
            adj[vi].push(ui);
        }

        if (inputIndex !== inputLines.length) {
            console.error('Input lines are more than expected');
            return;
        }

        dfs(1);
        preprocess();

        // Find distance between u and v
        console.log(get_distance(u, v));
    });
}

